package com.example.service;

import javax.crypto.Cipher;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.Arrays;

/**
 * AES Encryption Service Utility Class
 * 
 * Provides AES encryption functionality for secure message transmission
 * between client and server.
 * 
 * @author Example Team
 * @version 1.0
 */
public class AESService {

    private static final String ALGORITHM = "AES";
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";
    private static final int AES_KEY_SIZE = 16; // 128 bits

    /**
     * Private constructor to prevent instantiation of utility class
     */
    private AESService() {
        throw new UnsupportedOperationException("Utility class cannot be instantiated");
    }

    /**
     * Encrypts data using AES algorithm and returns hexadecimal string
     * 
     * @param key  The encryption key (will be normalized to 128/192/256 bits)
     * @param data The plaintext data to encrypt as byte array
     * @return Encrypted ciphertext as hexadecimal string
     * @throws IllegalArgumentException if key or data is null or empty
     * @throws RuntimeException if encryption fails due to cryptographic errors
     */
    public static String encrypt(String key, byte[] data) {
        // Input validation
        if (key == null || key.isEmpty()) {
            throw new IllegalArgumentException("Encryption key cannot be null or empty");
        }

        if (data == null || data.length == 0) {
            throw new IllegalArgumentException("Data to encrypt cannot be null or empty");
        }

        try {
            // Normalize the key to proper AES key size (128 bits = 16 bytes)
            byte[] keyBytes = normalizeKey(key);

            // Create AES secret key specification
            SecretKeySpec secretKeySpec = new SecretKeySpec(keyBytes, ALGORITHM);

            // Initialize cipher for encryption
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKeySpec);

            // Perform encryption
            byte[] encryptedBytes = cipher.doFinal(data);

            // Convert encrypted bytes to hexadecimal string
            return bytesToHex(encryptedBytes);

        } catch (IllegalArgumentException e) {
            // Re-throw validation exceptions
            throw e;
        } catch (Exception e) {
            // Wrap all cryptographic exceptions in RuntimeException
            throw new RuntimeException("AES encryption failed: " + e.getMessage(), e);
        }
    }

    /**
     * Normalizes the key string to a valid AES key size (16 bytes for AES-128)
     * Uses SHA-256 hash and truncates to required size
     * 
     * @param key The input key string
     * @return Normalized key bytes of proper length
     * @throws RuntimeException if key normalization fails
     */
    private static byte[] normalizeKey(String key) {
        try {
            // Convert key to bytes
            byte[] keyBytes = key.getBytes(StandardCharsets.UTF_8);

            // If key is already the correct size, use it directly
            if (keyBytes.length == AES_KEY_SIZE) {
                return keyBytes;
            }

            // If key is too short or too long, hash it with SHA-256
            // and truncate to AES_KEY_SIZE
            MessageDigest sha = MessageDigest.getInstance("SHA-256");
            byte[] hashedKey = sha.digest(keyBytes);

            // Return first 16 bytes for AES-128
            return Arrays.copyOf(hashedKey, AES_KEY_SIZE);

        } catch (Exception e) {
            throw new RuntimeException("Key normalization failed: " + e.getMessage(), e);
        }
    }

    /**
     * Converts byte array to hexadecimal string representation
     * 
     * @param bytes The byte array to convert
     * @return Hexadecimal string representation (lowercase)
     */
    private static String bytesToHex(byte[] bytes) {
        StringBuilder hexString = new StringBuilder(bytes.length * 2);

        for (byte b : bytes) {
            // Convert each byte to 2-digit hex string
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) {
                hexString.append('0');
            }
            hexString.append(hex);
        }

        return hexString.toString();
    }

    /**
     * Convenience method to encrypt string data
     * 
     * @param key  The encryption key
     * @param data The plaintext string to encrypt
     * @return Encrypted ciphertext as hexadecimal string
     * @throws IllegalArgumentException if key or data is null or empty
     * @throws RuntimeException if encryption fails
     */
    public static String encrypt(String key, String data) {
        if (data == null || data.isEmpty()) {
            throw new IllegalArgumentException("Data to encrypt cannot be null or empty");
        }

        byte[] dataBytes = data.getBytes(StandardCharsets.UTF_8);
        return encrypt(key, dataBytes);
    }
}
